arguments.prompt:
You are working in /tmp/sv-5f7d7592b03e47a49325852191bcba1a/ShipmentTracker. This is a Blazor Web App with Interactive WebAssembly render mode and Individual authentication (ASP.NET Core Identity with SQLite). The solution has two projects:
- `ShipmentTracker` (server) - hosts Components, Data, etc.
- `ShipmentTracker.Client` (WASM client) - has Pages that run on client

The template already has Identity wired up, a Home page, Counter, Weather, and Auth pages. I need you to transform this into a shipment tracking app for a logistics company.

## What to build:

### 1. Domain Model - Create `ShipmentTracker/Data/Shipment.cs`:
```csharp
namespace ShipmentTracker.Data;

public enum ShipmentStatus
{
    Pending,
    PickedUp,
    InTransit,
    OutForDelivery,
    Delivered,
    Cancelled
}

public class Shipment
{
    public int Id { get; set; }
    public string TrackingNumber { get; set; } = string.Empty;
    public string Origin { get; set; } = string.Empty;
    public string Destination { get; set; } = string.Empty;
    public ShipmentStatus Status { get; set; }
    public DateTime CreatedAt { get; set; }
    public DateTime? EstimatedDelivery { get; set; }
    public string? CustomerId { get; set; }
    public string? CustomerEmail { get; set; }
    public string? Notes { get; set; }
}
```

### 2. Update `ShipmentTracker/Data/ApplicationDbContext.cs` to add:
```csharp
public DbSet<Shipment> Shipments => Set<Shipment>();
```

### 3. Create a shared DTO in `ShipmentTracker.Client/Models/ShipmentDto.cs`:
```csharp
namespace ShipmentTracker.Client.Models;

public enum ShipmentStatus
{
    Pending,
    PickedUp,
    InTransit,
    OutForDelivery,
    Delivered,
    Cancelled
}

public class ShipmentDto
{
    public int Id { get; set; }
    public string TrackingNumber { get; set; } = string.Empty;
    public string Origin { get; set; } = string.Empty;
    public string Destination { get; set; } = string.Empty;
    public ShipmentStatus Status { get; set; }
    public DateTime CreatedAt { get; set; }
    public DateTime? EstimatedDelivery { get; set; }
    public string? CustomerEmail { get; set; }
    public string? Notes { get; set; }
}
```

### 4. Add API endpoints in the server project. Create `ShipmentTracker/Endpoints/ShipmentEndpoints.cs`:
```csharp
using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Data;
using ShipmentTracker.Client.Models;

namespace ShipmentTracker.Endpoints;

public static class ShipmentEndpoints
{
    public static void MapShipmentEndpoints(this WebApplication app)
    {
        var group = app.MapGroup("/api/shipments").RequireAuthorization();

        // Get all shipments (dispatchers)
        group.MapGet("/", async (ApplicationDbContext db) =>
        {
            var shipments = await db.Shipments
                .OrderByDescending(s => s.CreatedAt)
                .Select(s => new ShipmentDto
                {
                    Id = s.Id,
                    TrackingNumber = s.TrackingNumber,
                    Origin = s.Origin,
                    Destination = s.Destination,
                    Status = (Client.Models.ShipmentStatus)(int)s.Status,
                    CreatedAt = s.CreatedAt,
                    EstimatedDelivery = s.EstimatedDelivery,
                    CustomerEmail = s.CustomerEmail,
                    Notes = s.Notes
                })
                .ToListAsync();
            return Results.Ok(shipments);
        });

        // Track shipment by tracking number (customers)
        group.MapGet("/track/{trackingNumber}", async (string trackingNumber, ApplicationDbContext db) =>
        {
            var shipment = await db.Shipments
                .FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);
            if (shipment is null)
                return Results.NotFound();
            return Results.Ok(new ShipmentDto
            {
                Id = shipment.Id,
                TrackingNumber = shipment.TrackingNumber,
                Origin = shipment.Origin,
                Destination = shipment.Destination,
                Status = (Client.Models.ShipmentStatus)(int)shipment.Status,
                CreatedAt = shipment.CreatedAt,
                EstimatedDelivery = shipment.EstimatedDelivery,
                CustomerEmail = shipment.CustomerEmail,
                Notes = shipment.Notes
            });
        });

        // Create shipment
        group.MapPost("/", async (ShipmentDto dto, ApplicationDbContext db) =>
        {
            var shipment = new Shipment
            {
                TrackingNumber = dto.TrackingNumber,
                Origin = dto.Origin,
                Destination = dto.Destination,
                Status = (Data.ShipmentStatus)(int)dto.Status,
                CreatedAt = DateTime.UtcNow,
                EstimatedDelivery = dto.EstimatedDelivery,
                CustomerEmail = dto.CustomerEmail,
                Notes = dto.Notes
            };
            db.Shipments.Add(shipment);
            await db.SaveChangesAsync();
            dto.Id = shipment.Id;
            dto.CreatedAt = shipment.CreatedAt;
            return Results.Created($"/api/shipments/{shipment.Id}", dto);
        });

        // Update shipment status
        group.MapPut("/{id}", async (int id, ShipmentDto dto, ApplicationDbContext db) =>
        {
            var shipment = await db.Shipments.FindAsync(id);
            if (shipment is null)
                return Results.NotFound();
            shipment.Status = (Data.ShipmentStatus)(int)dto.Status;
            shipment.EstimatedDelivery = dto.EstimatedDelivery;
            shipment.Notes = dto.Notes;
            shipment.Destination = dto.Destination;
            await db.SaveChangesAsync();
            return Results.Ok();
        });
    }
}
```

### 5. Register endpoints in `Program.cs`. Add before `app.Run();`:
```csharp
app.MapShipmentEndpoints();
```
Also add `using ShipmentTracker.Endpoints;` at the top.

### 6. Add DB seed logic. Create `ShipmentTracker/Data/SeedData.cs`:
```csharp
using Microsoft.EntityFrameworkCore;

namespace ShipmentTracker.Data;

public static class SeedData
{
    public static async Task InitializeAsync(ApplicationDbContext db)
    {
        await db.Database.MigrateAsync();
        if (await db.Shipments.AnyAsync())
            return;

        db.Shipments.AddRange(
            new Shipment { TrackingNumber = "TRK-001234", Origin = "New York, NY", Destination = "Los Angeles, CA", Status = ShipmentStatus.InTransit, CreatedAt = DateTime.UtcNow.AddDays(-3), EstimatedDelivery = DateTime.UtcNow.AddDays(2), CustomerEmail = "alice@example.com", Notes = "Fragile" },
            new Shipment { TrackingNumber = "TRK-005678", Origin = "Chicago, IL", Destination = "Miami, FL", Status = ShipmentStatus.OutForDelivery, CreatedAt = DateTime.UtcNow.AddDays(-5), EstimatedDelivery = DateTime.UtcNow, CustomerEmail = "bob@example.com" },
            new Shipment { TrackingNumber = "TRK-009012", Origin = "Seattle, WA", Destination = "Denver, CO", Status = ShipmentStatus.Pending, CreatedAt = DateTime.UtcNow.AddDays(-1), EstimatedDelivery = DateTime.UtcNow.AddDays(4), CustomerEmail = "carol@example.com" },
            new Shipment { TrackingNumber = "TRK-003456", Origin = "Boston, MA", Destination = "Houston, TX", Status = ShipmentStatus.Delivered, CreatedAt = DateTime.UtcNow.AddDays(-7), EstimatedDelivery = DateTime.UtcNow.AddDays(-1), CustomerEmail = "dave@example.com" },
            new Shipment { TrackingNumber = "TRK-007890", Origin = "San Francisco, CA", Destination = "Portland, OR", Status = ShipmentStatus.PickedUp, CreatedAt = DateTime.UtcNow, EstimatedDelivery = DateTime.UtcNow.AddDays(3), CustomerEmail = "eve@example.com", Notes = "Keep refrigerated" }
        );
        await db.SaveChangesAsync();
    }
}
```

Call this from Program.cs right after `var app = builder.Build();`:
```csharp
using (var scope = app.Services.CreateScope())
{
    var db = scope.ServiceProvider.GetRequiredService<ApplicationDbContext>();
    await SeedData.InitializeAsync(db);
}
```

### 7. Client pages - Replace `ShipmentTracker.Client/Pages/Counter.razor` with a Dispatcher Dashboard page. Create these files:

**`ShipmentTracker.Client/Pages/Shipments.razor`** - Dispatcher view (list all shipments, filter by status, create new):
```razor
@page "/shipments"
@using ShipmentTracker.Client.Models
@using Microsoft.AspNetCore.Authorization
@using System.Net.Http.Json
@attribute [Authorize]
@inject HttpClient Http

<PageTitle>Shipment Dashboard</PageTitle>

<h2>Shipment Dashboard</h2>

<div class="row mb-3">
    <div class="col-md-4">
        <label class="form-label">Filter by Status</label>
        <select class="form-select" @bind="statusFilter">
            <option value="">All</option>
            @foreach (var s in Enum.GetValues<ShipmentStatus>())
            {
                <option value="@s">@s</option>
            }
        </select>
    </div>
    <div class="col-md-4">
        <label class="form-label">Search Destination</label>
        <input class="form-control" @bind="searchTerm" @bind:event="oninput" placeholder="Type to filter..." />
    </div>
    <div class="col-md-4 d-flex align-items-end">
        <button class="btn btn-primary" @onclick="ShowCreateForm">+ New Shipment</button>
    </div>
</div>

@if (showCreate)
{
    <div class="card mb-3">
        <div class="card-body">
            <h5>Create New Shipment</h5>
            <div class="row g-2">
                <div class="col-md-3">
                    <input class="form-control" @bind="newShipment.TrackingNumber" placeholder="Tracking #" />
                </div>
                <div class="col-md-3">
                    <input class="form-control" @bind="newShipment.Origin" placeholder="Origin" />
                </div>
                <div class="col-md-3">
                    <input class="form-control" @bind="newShipment.Destination" placeholder="Destination" />
                </div>
                <div class="col-md-3">
                    <input class="form-control" @bind="newShipment.CustomerEmail" placeholder="Customer Email" />
                </div>
            </div>
            <div class="row g-2 mt-2">
                <div class="col-md-3">
                    <input type="date" class="form-control" @bind="newShipment.EstimatedDelivery" />
                </div>
                <div class="col-md-3">
                    <input class="form-control" @bind="newShipment.Notes" placeholder="Notes" />
                </div>
                <div class="col-md-3">
                    <button class="btn btn-success" @onclick="CreateShipment">Create</button>
                    <button class="btn btn-secondary ms-1" @onclick="() => showCreate = false">Cancel</button>
                </div>
            </div>
            @if (!string.IsNullOrEmpty(createError))
            {
                <div class="alert alert-danger mt-2">@createError</div>
            }
        </div>
    </div>
}

@if (shipments is null)
{
    <p><em>Loading shipments...</em></p>
}
else
{
    <table class="table table-striped table-hover">
        <thead>
            <tr>
                <th>Tracking #</th>
                <th>Origin</th>
                <th>Destination</th>
                <th>Status</th>
                <th>Est. Delivery</th>
                <th>Customer</th>
                <th>Actions</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var shipment in FilteredShipments)
            {
                <tr>
                    <td>@shipment.TrackingNumber</td>
                    <td>@shipment.Origin</td>
                    <td>@shipment.Destination</td>
                    <td><span class="badge @GetStatusBadge(shipment.Status)">@shipment.Status</span></td>
                    <td>@shipment.EstimatedDelivery?.ToString("MMM dd, yyyy")</td>
                    <td>@shipment.CustomerEmail</td>
                    <td>
                        <select class="form-select form-select-sm" style="width: auto; display: inline-block;"
                                value="@((int)shipment.Status)"
                                @onchange="(e) => UpdateStatus(shipment, e)">
                            @foreach (var s in Enum.GetValues<ShipmentStatus>())
                            {
                                <option value="@((int)s)">@s</option>
                            }
                        </select>
                    </td>
                </tr>
            }
        </tbody>
    </table>
    <p class="text-muted">Showing @FilteredShipments.Count() of @shipments.Count shipments</p>
}

@code {
    private List<ShipmentDto>? shipments;
    private string statusFilter = "";
    private string searchTerm = "";
    private bool showCreate;
    private ShipmentDto newShipment = new();
    private string? createError;

    protected override async Task OnInitializedAsync()
    {
        await LoadShipments();
    }

    private async Task LoadShipments()
    {
        shipments = await Http.GetFromJsonAsync<List<ShipmentDto>>("/api/shipments");
    }

    private IEnumerable<ShipmentDto> FilteredShipments =>
        shipments!.Where(s =>
            (string.IsNullOrEmpty(statusFilter) || s.Status.ToString() == statusFilter) &&
            (string.IsNullOrEmpty(searchTerm) || s.Destination.Contains(searchTerm, StringComparison.OrdinalIgnoreCase)));

    private void ShowCreateForm()
    {
        showCreate = true;
        newShipment = new ShipmentDto { EstimatedDelivery = DateTime.UtcNow.AddDays(5) };
        createError = null;
    }

    private async Task CreateShipment()
    {
        if (string.IsNullOrWhiteSpace(newShipment.TrackingNumber) || string.IsNullOrWhiteSpace(newShipment.Destination))
        {
            createError = "Tracking number and destination are required.";
            return;
        }
        var response = await Http.PostAsJsonAsync("/api/shipments", newShipment);
        if (response.IsSuccessStatusCode)
        {
            showCreate = false;
            await LoadShipments();
        }
