    private List<ShipmentDto>? shipments;
    private string statusFilter = "";
    private string searchTerm = "";
    private bool showCreate;
    private ShipmentDto newShipment = new();
    private string? createError;

    protected override async Task OnInitializedAsync()
    {
        await LoadShipments();
    }

    private async Task LoadShipments()
    {
        shipments = await Http.GetFromJsonAsync<List<ShipmentDto>>("/api/shipments");
    }

    private IEnumerable<ShipmentDto> FilteredShipments =>
        shipments!.Where(s =>
            (string.IsNullOrEmpty(statusFilter) || s.Status.ToString() == statusFilter) &&
            (string.IsNullOrEmpty(searchTerm) || s.Destination.Contains(searchTerm, StringComparison.OrdinalIgnoreCase)));

    private void ShowCreateForm()
    {
        showCreate = true;
        newShipment = new ShipmentDto { EstimatedDelivery = DateTime.UtcNow.AddDays(5) };
        createError = null;
    }

    private async Task CreateShipment()
    {
        if (string.IsNullOrWhiteSpace(newShipment.TrackingNumber) || string.IsNullOrWhiteSpace(newShipment.Destination))
        {
            createError = "Tracking number and destination are required.";
            return;
        }
        var response = await Http.PostAsJsonAsync("/api/shipments", newShipment);
        if (response.IsSuccessStatusCode)
        {
            showCreate = false;
            await LoadShipments();
        }
        else
        {
            createError = "Failed to create shipment.";
        }
    }

    private async Task UpdateStatus(ShipmentDto shipment, ChangeEventArgs e)
    {
        var newStatus = (ShipmentStatus)int.Parse(e.Value!.ToString()!);
        shipment.Status = newStatus;
        await Http.PutAsJsonAsync($"/api/shipments/{shipment.Id}", shipment);
    }

    private string GetStatusBadge(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Cancelled => "bg-danger",
        _ => "bg-secondary"
    };
}
