```csharp
using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Data;
using ShipmentTracker.Client.Models;

namespace ShipmentTracker.Endpoints;

public static class ShipmentEndpoints
{
    public static void MapShipmentEndpoints(this WebApplication app)
    {
        var group = app.MapGroup("/api/shipments").RequireAuthorization();

        // Get all shipments (dispatchers)
        group.MapGet("/", async (ApplicationDbContext db) =>
        {
            var shipments = await db.Shipments
                .OrderByDescending(s => s.CreatedAt)
                .Select(s => new ShipmentDto
                {
                    Id = s.Id,
                    TrackingNumber = s.TrackingNumber,
                    Origin = s.Origin,
                    Destination = s.Destination,
                    Status = (Client.Models.ShipmentStatus)(int)s.Status,
                    CreatedAt = s.CreatedAt,
                    EstimatedDelivery = s.EstimatedDelivery,
                    CustomerEmail = s.CustomerEmail,
                    Notes = s.Notes
                })
                .ToListAsync();
            return Results.Ok(shipments);
        });

        // Track shipment by tracking number (customers)
        group.MapGet("/track/{trackingNumber}", async (string trackingNumber, ApplicationDbContext db) =>
        {
            var shipment = await db.Shipments
                .FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);
            if (shipment is null)
                return Results.NotFound();
            return Results.Ok(new ShipmentDto
            {
                Id = shipment.Id,
                TrackingNumber = shipment.TrackingNumber,
                Origin = shipment.Origin,
                Destination = shipment.Destination,
                Status = (Client.Models.ShipmentStatus)(int)shipment.Status,
                CreatedAt = shipment.CreatedAt,
                EstimatedDelivery = shipment.EstimatedDelivery,
                CustomerEmail = shipment.CustomerEmail,
                Notes = shipment.Notes
            });
        });

        // Create shipment
        group.MapPost("/", async (ShipmentDto dto, ApplicationDbContext db) =>
        {
            var shipment = new Shipment
            {
                TrackingNumber = dto.TrackingNumber,
                Origin = dto.Origin,
                Destination = dto.Destination,
                Status = (Data.ShipmentStatus)(int)dto.Status,
                CreatedAt = DateTime.UtcNow,
                EstimatedDelivery = dto.EstimatedDelivery,
                CustomerEmail = dto.CustomerEmail,
                Notes = dto.Notes
            };
            db.Shipments.Add(shipment);
            await db.SaveChangesAsync();
            dto.Id = shipment.Id;
            dto.CreatedAt = shipment.CreatedAt;
            return Results.Created($"/api/shipments/{shipment.Id}", dto);
        });

        // Update shipment status
        group.MapPut("/{id}", async (int id, ShipmentDto dto, ApplicationDbContext db) =>
        {
            var shipment = await db.Shipments.FindAsync(id);
            if (shipment is null)
                return Results.NotFound();
            shipment.Status = (Data.ShipmentStatus)(int)dto.Status;
            shipment.EstimatedDelivery = dto.EstimatedDelivery;
            shipment.Notes = dto.Notes;
            shipment.Destination = dto.Destination;
            await db.SaveChangesAsync();
            return Results.Ok();
        });
    }
}
```

