                CustomerEmail = dto.CustomerEmail,
                Notes = dto.Notes
            };
            db.Shipments.Add(shipment);
            await db.SaveChangesAsync();
            dto.Id = shipment.Id;
            dto.CreatedAt = shipment.CreatedAt;
            return Results.Created($"/api/shipments/{shipment.Id}", dto);
        });

        group.MapPut("/{id}", async (int id, ShipmentDto dto, ApplicationDbContext db) =>
        {
            var shipment = await db.Shipments.FindAsync(id);
            if (shipment is null)
                return Results.NotFound();
            shipment.Status = (Data.ShipmentStatus)(int)dto.Status;
            shipment.EstimatedDelivery = dto.EstimatedDelivery;
            shipment.Notes = dto.Notes;
            shipment.Destination = dto.Destination;
            await db.SaveChangesAsync();
            return Results.Ok();
        });
    }
}

@page "/shipments"
@using ShipmentTracker.Client.Models
@using Microsoft.AspNetCore.Authorization
@using System.Net.Http.Json
@attribute [Authorize]
@inject HttpClient Http

<PageTitle>Shipment Dashboard</PageTitle>

<h2>Shipment Dashboard</h2>

<div class="row mb-3">
    <div class="col-md-4">
        <label class="form-label">Filter by Status</label>
        <select class="form-select" @bind="statusFilter">
            <option value="">All</option>
            @foreach (var s in Enum.GetValues<ShipmentStatus>())
            {
                <option value="@s">@s</option>
            }
        </select>
    </div>
    <div class="col-md-4">
        <label class="form-label">Search Destination</label>
        <input class="form-control" @bind="searchTerm" @bind:event="oninput" placeholder="Type to filter..." />
    </div>
    <div class="col-md-4 d-flex align-items-end">
        <button class="btn btn-primary" @onclick="ShowCreateForm">+ New Shipment</button>
    </div>
</div>

@if (showCreate)
{
    <div class="card mb-3">
        <div class="card-body">
            <h5>Create New Shipment</h5>
            <div class="row g-2">
                <div class="col-md-3">
                    <input class="form-control" @bind="newShipment.TrackingNumber" placeholder="Tracking #" />
                </div>
                <div class="col-md-3">
                    <input class="form-control" @bind="newShipment.Origin" placeholder="Origin" />
                </div>
                <div class="col-md-3">
                    <input class="form-control" @bind="newShipment.Destination" placeholder="Destination" />
                </div>
                <div class="col-md-3">
                    <input class="form-control" @bind="newShipment.CustomerEmail" placeholder="Customer Email" />
                </div>
            </div>
            <div class="row g-2 mt-2">
                <div class="col-md-3">
                    <input type="date" class="form-control" @bind="newShipment.EstimatedDelivery" />
                </div>
                <div class="col-md-3">
                    <input class="form-control" @bind="newShipment.Notes" placeholder="Notes" />
                </div>
                <div class="col-md-3">
                    <button class="btn btn-success" @onclick="CreateShipment">Create</button>
                    <button class="btn btn-secondary ms-1" @onclick="() => showCreate = false">Cancel</button>
                </div>
            </div>
            @if (!string.IsNullOrEmpty(createError))
            {
                <div class="alert alert-danger mt-2">@createError</div>
            }
        </div>
    </div>
}

@if (shipments is null)
{
    <p><em>Loading shipments...</em></p>
}
else
{
    <table class="table table-striped table-hover">
        <thead>
            <tr>
                <th>Tracking #</th>
                <th>Origin</th>
                <th>Destination</th>
                <th>Status</th>
                <th>Est. Delivery</th>
                <th>Customer</th>
                <th>Actions</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var shipment in FilteredShipments)
            {
                <tr>
                    <td>@shipment.TrackingNumber</td>
                    <td>@shipment.Origin</td>
                    <td>@shipment.Destination</td>
                    <td><span class="badge @GetStatusBadge(shipment.Status)">@shipment.Status</span></td>
                    <td>@shipment.EstimatedDelivery?.ToString("MMM dd, yyyy")</td>
                    <td>@shipment.CustomerEmail</td>
                    <td>
                        <select class="form-select form-select-sm" style="width: auto; display: inline-block;"
                                value="@((int)shipment.Status)"
                                @onchange="(e) => UpdateStatus(shipment, e)">
                            @foreach (var s in Enum.GetValues<ShipmentStatus>())
                            {
                                <option value="@((int)s)">@s</option>
                            }
                        </select>
                    </td>
                </tr>
            }
        </tbody>
    </table>
    <p class="text-muted">Showing @FilteredShipments.Count() of @shipments.Count shipments</p>
}

@code {
    private List<ShipmentDto>? shipments;
    private string statusFilter = "";
    private string searchTerm = "";
    private bool showCreate;
    private ShipmentDto newShipment = new();
    private string? createError;

    protected override async Task OnInitializedAsync()
    {
        await LoadShipments();
    }

    private async Task LoadShipments()
    {
        shipments = await Http.GetFromJsonAsync<List<ShipmentDto>>("/api/shipments");
    }

    private IEnumerable<ShipmentDto> FilteredShipments =>
        shipments!.Where(s =>
            (string.IsNullOrEmpty(statusFilter) || s.Status.ToString() == statusFilter) &&
            (string.IsNullOrEmpty(searchTerm) || s.Destination.Contains(searchTerm, StringComparison.OrdinalIgnoreCase)));

    private void ShowCreateForm()
    {
        showCreate = true;
        newShipment = new ShipmentDto { EstimatedDelivery = DateTime.UtcNow.AddDays(5) };
        createError = null;
    }

    private async Task CreateShipment()
    {
        if (string.IsNullOrWhiteSpace(newShipment.TrackingNumber) || string.IsNullOrWhiteSpace(newShipment.Destination))
        {
            createError = "Tracking number and destination are required.";
            return;
        }
        var response = await Http.PostAsJsonAsync("/api/shipments", newShipment);
        if (response.IsSuccessStatusCode)
        {
            showCreate = false;
            await LoadShipments();
        }
        else
        {
            createError = "Failed to create shipment.";
        }
    }

    private async Task UpdateStatus(ShipmentDto shipment, ChangeEventArgs e)
    {
        var newStatus = (ShipmentStatus)int.Parse(e.Value!.ToString()!);
        shipment.Status = newStatus;
        await Http.PutAsJsonAsync($"/api/shipments/{shipment.Id}", shipment);
    }

    private string GetStatusBadge(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Cancelled => "bg-danger",
        _ => "bg-secondary"
    };
}

@page "/track"
@using ShipmentTracker.Client.Models
@using Microsoft.AspNetCore.Authorization
@using System.Net.Http.Json
@attribute [Authorize]
@inject HttpClient Http

<PageTitle>Track Shipment</PageTitle>

<h2>Track Your Shipment</h2>

<div class="row mb-4">
    <div class="col-md-6">
        <div class="input-group">
            <input class="form-control" @bind="trackingNumber" placeholder="Enter tracking number (e.g., TRK-001234)" @onkeydown="HandleKeyDown" />
            <button class="btn btn-primary" @onclick="TrackShipment">Track</button>
        </div>
    </div>
</div>

@if (isLoading)
{
    <p><em>Searching...</em></p>
}
else if (notFound)
{
    <div class="alert alert-warning">
        No shipment found with tracking number <strong>@searchedNumber</strong>. Please check the number and try again.
    </div>
}
else if (shipment is not null)
{
    <div class="card">
        <div class="card-header">
            <h5 class="mb-0">Shipment @shipment.TrackingNumber</h5>
        </div>
        <div class="card-body">
            <div class="row">
                <div class="col-md-6">
                    <dl>
                        <dt>Status</dt>
                        <dd><span class="badge @GetStatusBadge(shipment.Status) fs-6">@GetStatusDisplay(shipment.Status)</span></dd>
                        <dt>Origin</dt>
                        <dd>@shipment.Origin</dd>
                        <dt>Destination</dt>
                        <dd>@shipment.Destination</dd>
                    </dl>
                </div>
                <div class="col-md-6">
                    <dl>
                        <dt>Estimated Delivery</dt>
                        <dd>
                            @if (shipment.EstimatedDelivery.HasValue)
                            {
                                <span class="fs-5">@shipment.EstimatedDelivery.Value.ToString("dddd, MMMM dd, yyyy")</span>
                                @if (shipment.Status != ShipmentStatus.Delivered && shipment.Status != ShipmentStatus.Cancelled)
                                {
                                    var daysLeft = (shipment.EstimatedDelivery.Value - DateTime.UtcNow).Days;
                                    <br/><small class="text-muted">@(daysLeft > 0 ? $"{daysLeft} day(s) away" : "Expected today or overdue")</small>
                                }
                            }
                            else
                            {
                                <span>TBD</span>
                            }
                        </dd>
                        <dt>Shipped On</dt>
                        <dd>@shipment.CreatedAt.ToString("MMMM dd, yyyy")</dd>
                        @if (!string.IsNullOrEmpty(shipment.Notes))
                        {
                            <dt>Notes</dt>
                            <dd>@shipment.Notes</dd>
                        }
                    </dl>
                </div>
            </div>

            <!-- Status progress bar -->
            <div class="mt-3">
                <h6>Delivery Progress</h6>
                <div class="progress" style="height: 30px;">
                    <div class="progress-bar @GetProgressBarClass(shipment.Status)" role="progressbar"
                         style="width: @GetProgressPercent(shipment.Status)%">
                        @GetStatusDisplay(shipment.Status)
                    </div>
                </div>
            </div>
        </div>
    </div>
}

@code {
    private string trackingNumber = "";
    private string searchedNumber = "";
    private ShipmentDto? shipment;
    private bool isLoading;
    private bool notFound;

    private async Task HandleKeyDown(Microsoft.AspNetCore.Components.Web.KeyboardEventArgs e)
    {
        if (e.Key == "Enter")
            await TrackShipment();
    }

    private async Task TrackShipment()
    {
        if (string.IsNullOrWhiteSpace(trackingNumber)) return;
        isLoading = true;
        notFound = false;
        shipment = null;
        searchedNumber = trackingNumber.Trim();

        var response = await Http.GetAsync($"/api/shipments/track/{Uri.EscapeDataString(searchedNumber)}");
        if (response.IsSuccessStatusCode)
        {
            shipment = await response.Content.ReadFromJsonAsync<ShipmentDto>();
        }
        else
        {
            notFound = true;
        }
        isLoading = false;
    }

    private int GetProgressPercent(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => 10,
        ShipmentStatus.PickedUp => 30,
        ShipmentStatus.InTransit => 55,
        ShipmentStatus.OutForDelivery => 80,
        ShipmentStatus.Delivered => 100,
        ShipmentStatus.Cancelled => 100,
        _ => 0
    };

    private string GetProgressBarClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Cancelled => "bg-danger",
        _ => "bg-primary progress-bar-striped progress-bar-animated"
    };

    private string GetStatusDisplay(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "Pending",
        ShipmentStatus.PickedUp => "Picked Up",
        ShipmentStatus.InTransit => "In Transit",
        ShipmentStatus.OutForDelivery => "Out for Delivery",
        ShipmentStatus.Delivered => "Delivered",
        ShipmentStatus.Cancelled => "Cancelled",
        _ => status.ToString()
    };

    private string GetStatusBadge(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Cancelled => "bg-danger",
        _ => "bg-secondary"
    };
}

